<style>
    * {
        box-sizing: border-box;
        margin: 0;
        padding: 0;
    }

    #navbar {
        position: fixed;
        top: var(--height);
        left: 0;
        width: var(--width);
        height: calc(100vh - var(--height));
        background: var(--surface1);
        border-right: 0.5px solid var(--border);
        display: flex;
        flex-direction: column;
        justify-content: space-between;
        padding: 16px 0;
        z-index: 5;
    }

    .navbar-item {
        display: flex;
        flex-direction: column;
        align-items: center;
        gap: 4px;
    }

    .divider {
        width: 24px;
        height: 1px;
        background: var(--border);
        margin-bottom: 8px;
    }

    .navbar-button {
        position: relative;
        width: 40px;
        height: 40px;
        display: flex;
        align-items: center;
        justify-content: center;
